import java.io.*;   // for Serializable, InputStream, OutputStream etc., 
import java.net.*;    // includes Socket class (which represents a connection between two computers) - ServerSocket Class as well... ,InetAddress..etc,. and others like ReaderWriterLock ... .InputStreamReader....OutputStream.....Printwriter .... Bufferedreader ..Buffererequalsreadernonblockingwriters
  
public class java_53014_SocketServer_A07 {  // Creates the server. This will be run on port number A (34567). The client must connect to this same or a different, available Port Number for connection... .So as per question ...A01_PORT is chosen that has been pre-defined..
{   int PORT = 2987; // Defining the Server listening port.  Changed according to A03_PortNum and also used this in client program, on which user will connect.......also server should be able receiving data from multiple clients simultaneously but we can't start with a fixed value for simplicity of explanation..
    Socket s;   // Creates socket object.  This would represent the connection between our application (this Java file) and an actual TCP/IP client such as another running program on your computer.......and also allows communication within this machine to other machines connected via same network by using IP address of that machine or host name .
     ServerSocket ss; // Creates server socket.  This would be used for accepting incoming connections from any source, at the defined port number (specified in our s variable).   ...and also listens on all available unnamed ports and returns an instance representing one listener to these specified network interfaces with a bound system socket..
     try { // Creates block of code that will run once java program starts. This ensures correct initialization or termination ..... .  Java uses "try-catch" for error handling in its programs .........and also includes exception, IOException and so on....   ...to handle potential problems such as file not found exceptions etc..
     ss = new ServerSocket(PORT); // Set up a server socket with the port we want it to listen at.  This sets our connection point (which will be listening for connections from other machines) into motion ....... and also creates an instance of that setup using this particular set-up, so any client who wants connect can do....
     s = ss.accept(); // Accepts a request made by the incoming host on behalf of caller to open connection with TCP server socket ... .   If someone attempts access through previously established connections then it would block until some other requests come in from same or different source (host), otherwise this is blocking waiting for others
     PrintWriter out = new PrintWriter(s.getOutputStream(), true); // Creates a stream to write data into the connection that has been opened by server and sets whether auto flushing should be turned on - ie buffering, after which we can send all our messages .   "true" parameter means if this message was written using method flush() then those bytes will not get sent out again until they are read.
     BufferedReader in = new BufferedReader(new InputStreamReader (s.getInputStream())); // Creates a stream to accept data from connection that has been opened by server, and sets whether auto flushing should be turned off - ie buffering after which we can send all our messages .  The bytes read are returned as instances of the string class type..
      String greetingFromClient;   } // Block runs when java program starts. This ensures correct initialization or termination ....... in this case, it waits until a client connects to server and then once that happens .. both parties send message back over TCP connection  (like Hello Client), after they receive their messages from the other end of communication
    catch(IOException e) { // Catch block for handling exceptions. This runs if any exception is caught within this try-catch statement......   ... and also includes ioexception, socket not found etc to handle different types errors such as file/directory issues or network unreachable issue ...........and others
     } finally{    System.out.println("Closing the connection"); // This would close down any streams that are still open at this point in your code .. and also handles termination of JVM, ie garbage collection etc...... ...to make sure all resources like sockets/connections have been properly closed
      ss.close();  }    out .close ();   in .close() ; // This will close the streams up to this point - they can't be used after that because it would cause a StreamAlreadyClosedException... ...and also handles termination of JVM, ie garbage collection etc...... ..to make sure all resources like sockets/connections have been properly closed
 }  // Ends the try block where java program runs to ensure proper end if exception occurs during execution. Also it includes a finally code that will execute once regardless how we exit from this function (either through normal termination or an error). This closes down streams and also handles JVM cleanup etc.. ..to make sure all resources like sockets/connections have been properly closed
}  // Ends the main method which runs when java program starts to ensure proper end if exception occurs during execution. Also it includes a try block where our code will run, so we can handle exceptions and errors in ways that are more appropriate for this particular situation (like re-trying an operation or handling specific types of error cases)